descriptor.templateCss:
.sync-container { padding: 20px; background: #0d1b2a; border-radius: 12px; color: #fff; height: 100%; display: flex; flex-direction: column; font-family: 'Inter', sans-serif; border: 1px solid rgba(255,255,255,0.1); }
.sync-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 15px; }
.sync-stats { display: flex; gap: 15px; }
.stat-item { background: rgba(255,255,255,0.05); padding: 5px 15px; border-radius: 6px; }
.stat-item.out-of-sync { background: rgba(244, 67, 54, 0.15); color: #f44336; border: 1px solid rgba(244,67,54,0.3); }
.sync-filters { display: flex; gap: 10px; }
.filter-btn { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: #fff; padding: 6px 12px; border-radius: 4px; cursor: pointer; }
.filter-btn.active { background: #1b263b; border-color: #415a77; }
.table-wrapper { flex: 1; overflow-y: auto; }
.sync-table { width: 100%; border-collapse: collapse; }
.sync-table th { padding: 12px; font-size: 11px; color: #778da9; text-align: left; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid rgba(255,255,255,0.1); }
.sync-table td { padding: 12px; border-bottom: 1px solid rgba(255,255,255,0.05); font-size: 13px; }
.status-badge { padding: 3px 10px; border-radius: 12px; font-size: 10px; font-weight: 800; }
.status-badge.in-sync { background: rgba(76, 175, 80, 0.2); color: #4caf50; }
.status-badge.out-of-sync { background: rgba(244, 67, 54, 0.2); color: #f44336; animation: pulse 2s infinite; }
@keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.6; } 100% { opacity: 1; } }
.val-box { background: rgba(255,255,255,0.05); padding: 2px 8px; border-radius: 4px; min-width: 40px; display: inline-block; text-align: center; border: 1px solid rgba(255,255,255,0.1); }

descriptor.controllerScript:
self.onInit = function() {

    var $container = $(self.ctx.$container);

    self.ctx.state = {
        filterOutOfSync: false,
        pendingCommands: {},
        reportedStates: {}
    };

    function loadReportedStates() {

        try {
            self.ctx.state.reportedStates = JSON.parse(localStorage.getItem('roomControlState') || '{}');
        } catch (e) {
            self.ctx.state.reportedStates = {};
        }
    }

    function handleRoomControlState(evt) {

        if (!evt || !evt.detail || !evt.detail.entityName) {
            return;
        }

        self.ctx.state.reportedStates[evt.detail.entityName] = evt.detail;

        try {
            localStorage.setItem('roomControlState', JSON.stringify(self.ctx.state.reportedStates));
        } catch (e) {
        }

        if (self.ctx.updateSyncTable) {
            self.ctx.updateSyncTable();
        }
    }

    function loadPendingCommands() {

        try {
            self.ctx.state.pendingCommands = JSON.parse(localStorage.getItem('roomControlPending') || '{}');
        } catch (e) {
            self.ctx.state.pendingCommands = {};
        }
    }

    function handleRoomControlCommand(evt) {

        if (!evt || !evt.detail || !evt.detail.entityName) {
            return;
        }

        self.ctx.state.pendingCommands[evt.detail.entityName] = evt.detail;

        try {
            localStorage.setItem('roomControlPending', JSON.stringify(self.ctx.state.pendingCommands));
        } catch (e) {
        }

        if (self.ctx.updateSyncTable) {
            self.ctx.updateSyncTable();
        }
    }

    loadPendingCommands();
    loadReportedStates();
    window.addEventListener('roomControlCommand', handleRoomControlCommand);
    window.addEventListener('roomControlState', handleRoomControlState);

    self.ctx.state.pendingTimer = setInterval(function() {
        if (self.ctx.updateSyncTable) {
            self.ctx.updateSyncTable();
        }
    }, 1000);

    self.onDestroy = function() {
        window.removeEventListener('roomControlCommand', handleRoomControlCommand);
        window.removeEventListener('roomControlState', handleRoomControlState);
        if (self.ctx.state.pendingTimer) {
            clearInterval(self.ctx.state.pendingTimer);
        }
    };

    // =========================================================
    // HELPERS
    // =========================================================

    function normalizeString(v) {

        if (
            v === undefined ||
            v === null ||
            v === ''
        ) {
            return '---';
        }

        return String(v)
            .trim()
            .toUpperCase();
    }

    function normalizeNumber(v) {

        if (
            v === undefined ||
            v === null ||
            v === ''
        ) {
            return '---';
        }

        var n = parseInt(v);

        if (isNaN(n)) {
            return '---';
        }

        return n;
    }

    // =========================================================
    // VALUE EXTRACTOR
    // =========================================================
    // THIS IS THE IMPORTANT FIX
    // COAP VALUES COME AS OBJECTS
    // =========================================================

    function extractHvacValue(val) {

        if (
            val === undefined ||
            val === null
        ) {
            return '---';
        }

        // OBJECT PAYLOAD
        if (typeof val === 'object') {

            if (val.hvac_mode !== undefined) {
                return normalizeString(
                    val.hvac_mode
                );
            }

            if (val.value !== undefined) {
                return normalizeString(
                    val.value
                );
            }

            return '---';
        }

        return normalizeString(val);
    }

    function extractDimmerValue(val) {

        var n = parseInt(val);

        if (isNaN(n)) {
            return '---';
        }

        return n;
    }
    function dimmerFromLux(val) {

        var n = parseInt(val);

        if (isNaN(n)) {
            return '---';
        }

        var pct = Math.round((n / 1000) * 100);

        if (pct < 0) {
            pct = 0;
        }

        if (pct > 100) {
            pct = 100;
        }

        return pct;
    }


    // =========================================================
    // TABLE RENDER
    // =========================================================

    self.ctx.updateSyncTable = function() {

        var data = self.ctx.data;

        if (!data || !data.length) {
            return;
        }

        var entities = {};

        data.forEach(function(ds) {

            var entityName =
                ds.datasource.entityName;

            if (!entityName) {
                return;
            }

            if (!entities[entityName]) {

                entities[entityName] = {

                    name: entityName,

                    id:
                        ds.datasource.entityId,

                    lastSeen: 0,

                    desiredHvac: '---',
                    reportedHvac: '---',

                    desiredDimmer: '---',
                    reportedDimmer: '---',

                    desiredHvacUntil: 0,
                    desiredDimmerUntil: 0,

                    status: 'IN_SYNC'
                };
            }

            if (
                !ds.data ||
                !ds.data.length
            ) {
                return;
            }

            var latest =
                ds.data[ds.data.length - 1];

            var ts = latest[0];

            var val = latest[1];

            var key =
                (ds.dataKey.name || '')
                    .toLowerCase();

            var e =
                entities[entityName];


            // LAST SEEN

            if (ts > e.lastSeen) {
                e.lastSeen = ts;
            }

            // =================================================
            // HVAC
            // =================================================

            if (
                key.includes('hvac_command')
            ) {

                e.desiredHvac =
                    extractHvacValue(val);

                e.desiredHvacUntil = Date.now() + 5000;
            }

            else if (
                key === 'hvac_mode' ||
                key === 'hvac_status' ||
                key.includes('reported_hvac')
            ) {

                e.reportedHvac =
                    extractHvacValue(val);
            }

            // =================================================
            // DIMMER
            // =================================================

            else if (
                key.includes('dimmer_command')
            ) {

                e.desiredDimmer =
                    extractDimmerValue(val);

                e.desiredDimmerUntil = Date.now() + 5000;
            }

            else if (
                key === 'lighting_dimmer'
            ) {

                var dimmerVal =
                    extractDimmerValue(val);

                e.reportedDimmer =
                    dimmerVal;

                if (e.desiredDimmer === '---') {
                    e.desiredDimmer = dimmerVal;
                }
            }

            else if (
                key === 'light_level'
            ) {

                var dimmerFromLuxVal =
                    dimmerFromLux(val);

                if (dimmerFromLuxVal !== '---') {
                    e.reportedDimmer = dimmerFromLuxVal;

                    if (e.desiredDimmer === '---') {
                        e.desiredDimmer = dimmerFromLuxVal;
                    }
                }
            }

            // =================================================
            // OPTIONAL BACKEND STATUS
            // =================================================

            else if (
                key === 'sync_status'
            ) {

                e.status =
                    normalizeString(val);
            }
        });

        // =====================================================
        // AUTO STATUS CHECK
        // =====================================================

        var now = Date.now();

        var pending = self.ctx.state.pendingCommands || {};

        var reportedStates = self.ctx.state.reportedStates || {};

        Object.keys(reportedStates).forEach(function(name) {

            var state = reportedStates[name];

            if (!state) {
                return;
            }

            var e = entities[name];

            if (!e) {
                return;
            }

            if (state.lighting_dimmer !== undefined) {
                e.reportedDimmer = extractDimmerValue(state.lighting_dimmer);
                if (e.desiredDimmer === '---') {
                    e.desiredDimmer = e.reportedDimmer;
                }
            }
        });


        Object.keys(pending).forEach(function(name) {

            var cmd = pending[name];

            if (!cmd || !cmd.expiresAt || now > cmd.expiresAt) {
                delete pending[name];
                return;
            }

            var e = entities[name];

            if (!e) {
                return;
            }

            if (cmd.type === 'hvac') {
                e.desiredHvac = extractHvacValue(cmd.value);
                e.desiredHvacUntil = cmd.expiresAt;
            }

            if (cmd.type === 'dimmer') {
                e.desiredDimmer = extractDimmerValue(cmd.value);
                e.desiredDimmerUntil = cmd.expiresAt;
            }
        });

        Object.values(entities)
            .forEach(function(e) {

            if (e.desiredHvacUntil && now > e.desiredHvacUntil) {
                e.desiredHvac = '---';
                e.desiredHvacUntil = 0;
            }

            if (e.desiredDimmerUntil && now > e.desiredDimmerUntil) {
                e.desiredDimmer = '---';
                e.desiredDimmerUntil = 0;
            }

            if (e.reportedDimmer === '---' && e.desiredDimmer !== '---') {
                e.reportedDimmer = e.desiredDimmer;
            }

            try {
                localStorage.setItem('roomControlPending', JSON.stringify(pending));
            } catch (e) {
            }


            // HVAC CHECK

            var hvacOk = true;

            if (
                e.desiredHvac !== '---' &&
                e.reportedHvac !== '---'
            ) {

                hvacOk =
                    normalizeString(
                        e.desiredHvac
                    ) ===
                    normalizeString(
                        e.reportedHvac
                    );
            }

            // DIMMER CHECK

            var dimmerOk = true;

            if (
                e.desiredDimmer !== '---' &&
                e.reportedDimmer !== '---'
            ) {

                dimmerOk =
                    parseInt(e.desiredDimmer) ===
                    parseInt(e.reportedDimmer);
            }

            // IMPORTANT:
            // IF ONE SIDE IS --- DON'T FORCE
            // OUT OF SYNC

            e.status =
                (
                    hvacOk &&
                    dimmerOk
                )
                ? 'IN_SYNC'
                : 'OUT_OF_SYNC';
        });

        // =====================================================
        // RENDER TABLE
        // =====================================================

        var rows =
            Object.values(entities);

        var total = 0;

        var outCount = 0;

        var $body =
            $('#syncTableBody', $container);

        $body.empty();

        rows.forEach(function(e) {

            total++;

            var isOut =
                e.status ===
                'OUT_OF_SYNC';

            if (isOut) {
                outCount++;
            }

            if (
                self.ctx.state.filterOutOfSync &&
                !isOut
            ) {
                return;
            }

            var row = $('<tr>');

            row.append(
                $('<td>').text(e.name)
            );

            row.append(
                $('<td>').text(
                    e.lastSeen
                    ? new Date(e.lastSeen)
                        .toLocaleTimeString()
                    : '---'
                )
            );

            row.append(
                $('<td>').html(
                    '<span class="val-box">' +
                    e.desiredHvac +
                    '</span>'
                )
            );

            row.append(
                $('<td>').html(
                    '<span class="val-box">' +
                    e.reportedHvac +
                    '</span>'
                )
            );

            row.append(
                $('<td>').html(
                    '<span class="val-box">' +
                    (
                        e.desiredDimmer === '---'
                        ? '---'
                        : e.desiredDimmer + '%'
                    ) +
                    '</span>'
                )
            );

            row.append(
                $('<td>').html(
                    '<span class="val-box">' +
                    (
                        e.reportedDimmer === '---'
                        ? '---'
                        : e.reportedDimmer + '%'
                    ) +
                    '</span>'
                )
            );

            row.append(
                $('<td>').html(
                    '<span class="status-badge ' +
                    (
                        isOut
                        ? 'out-of-sync'
                        : 'in-sync'
                    ) +
                    '">' +
                    e.status +
                    '</span>'
                )
            );

            $body.append(row);
        });

        $('#totalCount', $container)
            .text(total);

        $('#outOfSyncCount', $container)
            .text(outCount);
    };

    // =========================================================
    // FILTERS
    // =========================================================

    $('#btnAll', $container)
        .click(function() {

        $('.filter-btn', $container)
            .removeClass('active');

        $(this).addClass('active');

        self.ctx.state.filterOutOfSync =
            false;

        self.ctx.updateSyncTable();
    });

    $('#btnOutOfSync', $container)
        .click(function() {

        $('.filter-btn', $container)
            .removeClass('active');

        $(this).addClass('active');

        self.ctx.state.filterOutOfSync =
            true;

        self.ctx.updateSyncTable();
    });
};

// =============================================================
// DATA UPDATED
// =============================================================

self.onDataUpdated = function() {

    if (
        self.ctx.updateSyncTable
    ) {

        self.ctx.updateSyncTable();
    }
};

// =============================================================
// PARAMETERS
// =============================================================

self.typeParameters = function() {

    return {

        maxDatasources: -1,

        maxDataKeys: 20,

        singleEntity: false,

        useDatasource: true
    };
};
